async function sendTransaction(to, value) {
    const account = await web3.eth.accounts.privateKeyToAccount(wallet1.privateKey); // Set sender account based on the wallet configuration
  
    const tx = {
        to: to,
        value: web3.utils.toWei(value.toString(), 'ether'), 
        gas: 2000000 
    };
    
    const signedTx = await account.signTransaction(tx); // Sign the transaction with wallet's private key
  
    return await web3.eth.sendSignedTransaction(signedTx.rawTransaction); // Send the signed transaction to network
}

